import{_ as t,o as n,c as s,a3 as r}from"./chunks/framework.LBeL10WQ.js";const p=JSON.parse(`{"title":"Comment fonctionne le Retail Media - getinside","description":"Comprenez l'écosystème retail media de getinside. Du transfert de confiance au matching contextuel, découvrez les 3 leviers de monétisation.","frontmatter":{"title":"Comment fonctionne le Retail Media - getinside","description":"Comprenez l'écosystème retail media de getinside. Du transfert de confiance au matching contextuel, découvrez les 3 leviers de monétisation.","keywords":["retail media","matching contextuel","endorsed advertising","monétisation colis","plateforme d'affiliation","trust transfer","getinside","e-commerce growth"],"image":"/images/gi-keyvisual.svg"},"headers":[],"relativePath":"start-here/why-it-works.md","filePath":"start-here/why-it-works.md"}`),i={name:"start-here/why-it-works.md"};function o(a,e,c,l,d,u){return n(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="comment-ca-fonctionne-l-ecosysteme-retail-media-de-getinside" tabindex="-1">Comment ça fonctionne ? L&#39;Écosystème Retail Media de getinside <a class="header-anchor" href="#comment-ca-fonctionne-l-ecosysteme-retail-media-de-getinside" aria-label="Permalink to &quot;Comment ça fonctionne ? L&#39;Écosystème Retail Media de getinside&quot;">​</a></h1><p>Comprendre le fonctionnement opérationnel de <strong>getinside</strong>, la plateforme retail media qui crée un cycle vertueux entre <strong>monétisation</strong> (pour retailers) et <strong>acquisition qualifiée</strong> (pour annonceurs).</p><p><strong>getinside</strong> utilise le <strong>matching contextuel</strong> — le placement intelligent d&#39;offres complémentaires auprès de consommateurs au moment exact où ils sont les plus réceptifs — pour créer des campagnes endorsed (recommandées par le retailer) avec des <strong>taux de conversion jusqu&#39;à 5x supérieurs</strong> au display classique.</p><table tabindex="0"><thead><tr><th>Acteur</th><th>Action</th><th>Flux</th></tr></thead><tbody><tr><td>📦 <strong>E-commerçant</strong></td><td>Envoie ses colis et emails à ses clients</td><td>Inventaire disponible</td></tr><tr><td>⚡ <strong>Plateforme</strong></td><td>Connecte l&#39;inventaire aux marques partenaires</td><td>Matching contextuel</td></tr><tr><td>📢 <strong>Annonceur</strong></td><td>Achète cet espace pour diffuser son offre</td><td>Campagnes distribuées</td></tr><tr><td>💰 <strong>Réinvestissement</strong></td><td>Les revenus financent votre propre acquisition</td><td>Croissance auto-alimentée</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Le Cycle Vertueux</p><p>L&#39;e-commerçant monétise ses colis et emails, reçoit des revenus immédiatement accessibles via son Wallet, puis les réinvestit pour acquérir sa propre audience chez des partenaires complémentaires. Un cycle fermé qui transforme les centres de coûts en moteurs de croissance.</p></div><h2 id="le-transfert-de-confiance-endorsement" tabindex="-1">Le Transfert de Confiance (Endorsement) <a class="header-anchor" href="#le-transfert-de-confiance-endorsement" aria-label="Permalink to &quot;Le Transfert de Confiance (Endorsement)&quot;">​</a></h2><p>Le point commun entre un colis, une newsletter et un post social d&#39;une marque :</p><ul><li><strong>La Relation Client :</strong> Le consommateur a déjà acheté ou s&#39;est abonné volontairement.</li><li><strong>La Crédibilité :</strong> Il fait confiance au retailer (le e-commerçant).</li><li><strong>L&#39;Attention :</strong> Il attend ce contenu (suivi de commande, nouveautés).</li></ul><div class="tip custom-block"><p class="custom-block-title">L&#39;Effet de Halo</p><p>En vous insérant dans cet écosystème, votre marque bénéficie instantanément de ce capital confiance. Vous n&#39;êtes plus un intrus, vous êtes un <strong>partenaire recommandé</strong>.</p><p>Le format <strong>Emailing Dédié</strong> pousse cet effet au maximum : le retailer rédige lui-même le message à la 1ère personne (&quot;Chers clients, voici notre coup de cœur...&quot;), transformant la marque partenaire en extension naturelle de ses recommandations.</p></div><h2 id="pour-l-e-commercant-la-logique-economique" tabindex="-1">Pour l&#39;E-commerçant : La logique économique <a class="header-anchor" href="#pour-l-e-commercant-la-logique-economique" aria-label="Permalink to &quot;Pour l&#39;E-commerçant : La logique économique&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Le cercle vertueux du Réinvestissement</p><p>getinside n&#39;est pas seulement une régie, c&#39;est un accélérateur de croissance. Ces revenus contribuent directement à votre <strong>EBITDA</strong>, avec des <strong>marges nettes de 65-70%</strong> qui reflètent l&#39;efficacité de vos actifs logistiques existants.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>1. Monétisation</strong><p>Vos colis et emails génèrent du cash grâce aux annonceurs tiers.</p></div><div class="gi-value-card"><strong>2. Transfert Instantané</strong><p>Vos revenus sont disponibles sur votre Wallet. Pas besoin d&#39;attendre un virement bancaire.</p></div><div class="gi-value-card"><strong>3. Acquisition</strong><p>Vous réinvestissez ce budget pour diffuser VOS campagnes chez des partenaires complémentaires.</p></div></div><p><em>Résultat : Vous financez votre acquisition client... grâce à vos propres colis !</em></p></div><h2 id="_3-leviers-1-ecosysteme" tabindex="-1">3 Leviers, 1 Écosystème <a class="header-anchor" href="#_3-leviers-1-ecosysteme" aria-label="Permalink to &quot;3 Leviers, 1 Écosystème&quot;">​</a></h2><p>Ne laissez aucun asset inexploité. getinside valorise vos points de contact physiques et digitaux pour maximiser la couverture.</p><table tabindex="0"><thead><tr><th>Levier</th><th>Force Clé</th><th>Rôle Stratégique</th></tr></thead><tbody><tr><td>📦 <strong>Insertion Colis</strong></td><td><strong>100% d&#39;attention</strong> — hyper-concentration du consommateur pendant l&#39;unboxing</td><td>Ancrage mémoriel, prise en main physique, conversion maximale</td></tr><tr><td>📧 <strong>Emailing Dédié</strong></td><td><strong>Volume &amp; Réactivité</strong></td><td>Trafic immédiat, offres &quot;Flash&quot;, ciblage comportemental</td></tr><tr><td>📱 <strong>Social Ads</strong></td><td><strong>Viralité &amp; Data</strong></td><td>Notoriété, preuve sociale, recrutement jeune</td></tr></tbody></table><h2 id="l-expertise-getinside-votre-accelerateur" tabindex="-1">L&#39;Expertise getinside : Votre Accélérateur <a class="header-anchor" href="#l-expertise-getinside-votre-accelerateur" aria-label="Permalink to &quot;L&#39;Expertise getinside : Votre Accélérateur&quot;">​</a></h2><p>Le Retail Media est puissant, mais complexe à opérer seul.</p><table tabindex="0"><thead><tr><th>🚫 Sans getinside</th><th>✅ Avec getinside</th></tr></thead><tbody><tr><td>Négocier avec 50 sites un par un.</td><td>Un interlocuteur unique.</td></tr><tr><td>Gérer 50 factures et contrats.</td><td>Une facture unique centralisée.</td></tr><tr><td>Risque de qualité d&#39;impression.</td><td>Processus logistique et RSE certifié.</td></tr><tr><td>Aucune standardisation des formats.</td><td>Tracking uniformisé.</td></tr><tr><td>Reporting éparpillé.</td><td>Conseil stratégique inclus.</td></tr></tbody></table><h2 id="la-qualite-comme-moteur-de-croissance" tabindex="-1">La Qualité comme Moteur de Croissance <a class="header-anchor" href="#la-qualite-comme-moteur-de-croissance" aria-label="Permalink to &quot;La Qualité comme Moteur de Croissance&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">⭐ Le Score Distributeur : Votre clé d&#39;accès</p><p>Chaque partenaire e-commerçant reçoit un <strong>Score Distributeur</strong> (1-5 étoiles) basé sur <strong>7 critères clés</strong> : respect des délais, qualité de tracking, taux d&#39;erreur, conformité RGPD, taux de réclamations, intégration API et réactivité.</p><p>Ce score détermine votre <strong>visibilité dans le moteur de recherche de la plateforme</strong> et votre accès prioritaire aux campagnes premium. Une excellente exécution renforce ce score, crée une confiance durable avec les annonceurs, et ouvre les portes à des opportunités de revenus croissants.</p></div><h2 id="le-matching-contextuel-la-pertinence-avant-tout" tabindex="-1">Le Matching Contextuel : La pertinence avant tout <a class="header-anchor" href="#le-matching-contextuel-la-pertinence-avant-tout" aria-label="Permalink to &quot;Le Matching Contextuel : La pertinence avant tout&quot;">​</a></h2><p>La puissance de getinside réside dans la <strong>cohérence contextuelle</strong>. Nous proposons des <strong>offres complémentaires</strong> au moment précis où le consommateur en a besoin.</p><div class="gi-value-grid"><div class="gi-value-card"><span>🍷 <strong>L&#39;épicurien</strong> (Newsletter)</span><p>Déclencheur : Achat de fromage affiné.</p><p>➔ Offre poussée : Une box de vins sélectionnés.</p></div><div class="gi-value-card"><span>🏃 <strong>Le Sportif</strong> (Social Ads)</span><p>Déclencheur : Follower d&#39;une marque d&#39;équipement running.</p><p>➔ Offre poussée : Programme de nutrition &amp; récupération.</p></div><div class="gi-value-card"><span>👶 <strong>Les Jeunes Parents</strong> (Insertion Colis)</span><p>Déclencheur : Commande de jouets d&#39;éveil.</p><p>➔ Offre poussée : Vêtements bio pour enfants.</p></div><div class="gi-value-card"><span>🪴 <strong>Home Sweet Home</strong> (Insertion Colis)</span><p>Déclencheur : Achat de linge de lit en lin.</p><p>➔ Offre poussée : Abonnement fleurs fraîches.</p></div></div><div class="tip custom-block"><p class="custom-block-title">Prêt à activer votre croissance ?</p><p>Que vous soyez annonceur cherchant de nouveaux clients ou e-commerçant voulant monétiser vos colis, l&#39;écosystème getinside est conçu pour vous.</p><p><a href="mailto:studio@getinside.com" target="_blank" rel="noreferrer">Discuter de mon projet</a></p></div>',23)])])}const g=t(i,[["render",o]]);export{p as __pageData,g as default};
